# Protocol constants
PROTOCOL_VERSION = 1
MAX_UDP_PAYLOAD = 1400  # Safe MTU-friendly size
FRAGMENT_HEADER_SIZE = 16  # protocol_ver(1) + type(1) + request_id(4) + fragment_id(2) + total_fragments(2) + payload_size(2) + checksum(4)

# Message types
MSG_STATUS_REQUEST = 0x01
MSG_STATUS_RESPONSE = 0x02
MSG_PING_REQUEST = 0x03
MSG_PING_RESPONSE = 0x04
MSG_PLAYER_LIST_REQUEST = 0x05
MSG_PLAYER_LIST_RESPONSE = 0x06
MSG_RULES_REQUEST = 0x07
MSG_RULES_RESPONSE = 0x08
MSG_CHALLENGE_REQUEST = 0x09
MSG_CHALLENGE_RESPONSE = 0x0A

# Rate limiting
MAX_REQUESTS_PER_SECOND = 10
RATE_LIMIT_WINDOW = 1.0


class RateLimiter:
    """Simple per-IP rate limiter to prevent amplification attacks."""

    def __init__(self, max_requests: int = MAX_REQUESTS_PER_SECOND, window: float = RATE_LIMIT_WINDOW):
        self.max_requests = max_requests
        self.window = window
        self._requests: Dict[str, List[float]] = {}
        self._lock = threading.Lock()

    def is_allowed(self, ip: str) -> bool:
        now = time.time()
        with self._lock:
            if ip not in self._requests:
                self._requests[ip] = [now]
                return True

            # Clean old entries
            self._requests[ip] = [t for t in self._requests[ip] if now - t < self.window]

            if len(self._requests[ip]) >= self.max_requests:
                return False

            self._requests[ip].append(now)
            return True

    def cleanup(self):
        """Remove stale entries."""
        now = time.time()
        with self._lock:
            stale_ips = [ip for ip, times in self._requests.items()
                         if all(now - t >= self.window * 10 for t in times)]
            for ip in stale_ips:
                del self._requests[ip]


class ChallengeManager:
    """
    Challenge-response system to prevent IP spoofing / amplification attacks.
    Clients must first obtain a challenge token before requesting large responses.
    """

    def __init__(self, expiry: float = 30.0):
        self.expiry = expiry
        self._challenges: Dict[str, tuple] = {}  # addr_key -> (challenge, timestamp)
        self._lock = threading.Lock()

    def generate_challenge(self, addr: tuple) -> int:
        addr_key = f"{addr[0]}:{addr[1]}"
        challenge = struct.unpack('!I', hashlib.sha256(
            f"{addr_key}{time.time()}{uuid.uuid4()}".encode()
        ).digest()[:4])[0]

        with self._lock:
            self._challenges[addr_key] = (challenge, time.time())

        return challenge

    def verify_challenge(self, addr: tuple, challenge: int) -> bool:
        addr_key = f"{addr[0]}:{addr[1]}"
        with self._lock:
            if addr_key not in self._challenges:
                return False

            stored_challenge, timestamp = self._challenges[addr_key]
            if time.time() - timestamp > self.expiry:
                del self._challenges[addr_key]
                return False

            if stored_challenge == challenge:
                del self._challenges[addr_key]
                return True

            return False

    def cleanup(self):
        now = time.time()
        with self._lock:
            stale = [k for k, (_, ts) in self._challenges.items() if now - ts > self.expiry]
            for k in stale:
                del self._challenges[k]


class GameServer:
    """UDP Game Server with status query support."""

    def __init__(self, host: str = "0.0.0.0", port: int = 27015):
        self.host = host
        self.port = port
        self.server_info = ServerInfo()
        self.players: Dict[str, Player] = {}
        self._players_lock = threading.Lock()
        self._running = False
        self._socket: Optional[socket.socket] = None
        self.rate_limiter = RateLimiter()
        self.challenge_manager = ChallengeManager()
        self._request_id_counter = 0
        self._cleanup_interval = 30.0

        # Configure default rules
        self.server_info.rules = {
            "friendly_fire": "off",
            "allow_spectators": "on",
            "gravity": "800",
            "round_time": "120",
        }

        # Message handlers
        self._handlers = {
            MSG_STATUS_REQUEST: self._handle_status_request,
            MSG_PING_REQUEST: self._handle_ping_request,
            MSG_PLAYER_LIST_REQUEST: self._handle_player_list_request,
            MSG_RULES_REQUEST: self._handle_rules_request,
            MSG_CHALLENGE_REQUEST: self._handle_challenge_request,
        }

    def start(self):
        """Start the game server."""
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)

        # Set receive buffer size
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 65536)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_SNDBUF, 65536)

        self._socket.bind((self.host, self.port))
        self._socket.settimeout(1.0)

        self._running = True

        # Start cleanup thread
        self._cleanup_thread = threading.Thread(target=self._cleanup_loop, daemon=True)
        self._cleanup_thread.start()

        logger.info(f"Game server started on {self.host}:{self.port}")

        self._listen_loop()

    def stop(self):
        """Stop the game server."""
        self._running = False
        if self._socket:
            self._socket.close()
        logger.info("Game server stopped")

    def add_player(self, name: str, team: str = "", ip_address: str = "") -> Player:
        """Add a player to the server."""
        with self._players_lock:
            if len(self.players) >= self.server_info.max_players:
                raise ValueError("Server is full")

            player_id = str(uuid.uuid4())[:8]
            player = Player(
                player_id=player_id,
                name=name,
                team=team,
                ip_address=ip_address,
            )
            self.players[player_id] = player
            logger.info(f"Player '{name}' ({player_id}) joined the server")

            if len(self.players) >= 2 and self.server_info.game_state == GameState.WAITING:
                self.server_info.game_state = GameState.IN_PROGRESS

            return player

    def remove_player(self, player_id: str):
        """Remove a player from the server."""
        with self._players_lock:
            if player_id in self.players:
                player = self.players.pop(player_id)
                logger.info(f"Player '{player.name}' ({player_id}) left the server")

                if len(self.players) < 2:
                    self.server_info.game_state = GameState.WAITING

    def update_player(self, player_id: str, **kwargs):
        """Update player attributes."""
        with self._players_lock:
            if player_id in self.players:
                for key, value in kwargs.items():
                    if hasattr(self.players[player_id], key):
                        setattr(self.players[player_id], key, value)

    def _listen_loop(self):
        """Main listening loop for UDP packets."""
        while self._running:
            try:
                data, addr = self._socket.recvfrom(4096)
                if data:
                    # Process in a thread to not block the main loop
                    threading.Thread(
                        target=self._handle_packet,
                        args=(data, addr),
                        daemon=True
                    ).start()
            except socket.timeout:
                continue
            except OSError:
                if self._running:
                    logger.error("Socket error in listen loop")
                break

    def _handle_packet(self, data: bytes, addr: tuple):
        """Handle an incoming UDP packet."""
        ip = addr[0]

        # Rate limiting
        if not self.rate_limiter.is_allowed(ip):
            logger.warning(f"Rate limited: {ip}")
            return

        if len(data) < 2:
            return

        try:
            protocol_version = data[0]
            msg_type = data[1]

            if protocol_version != PROTOCOL_VERSION:
                logger.debug(f"Unknown protocol version {protocol_version} from {addr}")
                return

            handler = self._handlers.get(msg_type)
            if handler:
                handler(data[2:], addr)
            else:
                logger.debug(f"Unknown message type 0x{msg_type:02x} from {addr}")

        except Exception as e:
            logger.error(f"Error handling packet from {addr}: {e}")

    def _handle_challenge_request(self, payload: bytes, addr: tuple):
        """Handle a challenge request - must be done before large queries."""
        challenge = self.challenge_manager.generate_challenge(addr)
        response = struct.pack('!BBI', PROTOCOL_VERSION, MSG_CHALLENGE_RESPONSE, challenge)
        self._send_raw(response, addr)
        logger.debug(f"Challenge sent to {addr}")

    def _handle_status_request(self, payload: bytes, addr: tuple):
        """
        Handle a full status request.
        Requires a valid challenge to prevent amplification attacks.
        """
        if len(payload) < 4:
            logger.debug(f"Status request too short from {addr}, sending challenge hint")
            # Send a small response telling client to get a challenge first
            self._send_challenge_required(addr)
            return

        challenge = struct.unpack('!I', payload[:4])[0]
        if not self.challenge_manager.verify_challenge(addr, challenge):
            logger.warning(f"Invalid challenge from {addr}")
            self._send_challenge_required(addr)
            return

        # Build full status response
        with self._players_lock:
            player_list = [p.to_dict() for p in self.players.values()]

        status = {
            "server": self.server_info.to_dict(),
            "players": player_list,
            "player_count": len(player_list),
            "timestamp": time.time(),
        }

        response_json = json.dumps(status, separators=(',', ':')).encode('utf-8')
        self._send_fragmented(MSG_STATUS_RESPONSE, response_json, addr)

    def _handle_ping_request(self, payload: bytes, addr: tuple):
        """Handle a simple ping request - small response, no challenge needed."""
        # Extract client timestamp if provided
        client_time = 0
        if len(payload) >= 8:
            client_time = struct.unpack('!d', payload[:8])[0]

        with self._players_lock:
            player_count = len(self.players)

        # Small response: echo client time + basic info
        response = struct.pack(
            '!BBdBB',
            PROTOCOL_VERSION,
            MSG_PING_RESPONSE,
            client_time,
            player_count,
            self.server_info.max_players,
        )
        # Append server name (length-prefixed)
        name_bytes = self.server_info.server_name.encode('utf-8')[:255]
        response += struct.pack('!B', len(name_bytes)) + name_bytes

        # Append map name
        map_bytes = self.server_info.map_name.encode('utf-8')[:255]
        response += struct.pack('!B', len(map_bytes)) + map_bytes

        self._send_raw(response, addr)

    def _handle_player_list_request(self, payload: bytes, addr: tuple):
        """Handle player list request - requires challenge."""
        if len(payload) < 4:
            self._send_challenge_required(addr)
            return

        challenge = struct.unpack('!I', payload[:4])[0]
        if not self.challenge_manager.verify_challenge(addr, challenge):
            self._send_challenge_required(addr)
            return

        with self._players_lock:
            player_list = [p.to_dict() for p in self.players.values()]

        data = {
            "players": player_list,
            "player_count": len(player_list),
            "max_players": self.server_info.max_players,
        }

        response_json = json.dumps(data, separators=(',', ':')).encode('utf-8')
        self._send_fragmented(MSG_PLAYER_LIST_RESPONSE, response_json, addr)

    def _handle_rules_request(self, payload: bytes, addr: tuple):
        """Handle rules/settings request - requires challenge."""
        if len(payload) < 4:
            self._send_challenge_required(addr)
            return

        challenge = struct.unpack('!I', payload[:4])[0]
        if not self.challenge_manager.verify_challenge(addr, challenge):
            self._send_challenge_required(addr)
            return

        data = {
            "rules": self.server_info.rules,
            "game_mode": self.server_info.game_mode,
            "map_name": self.server_info.map_name,
            "time_limit": self.server_info.time_limit,
            "score_limit": self.server_info.score_limit,
        }

        response_json = json.dumps(data, separators=(',', ':')).encode('utf-8')
        self._send_fragmented(MSG_RULES_RESPONSE, response_json, addr)

    def _send_challenge_required(self, addr: tuple):
        """Send a small packet indicating a challenge is required."""
        response = struct.pack('!BBB', PROTOCOL_VERSION, 0xFF, 0x01)  # 0xFF = error, 0x01 = challenge required
        self._send_raw(response, addr)

    def _send_fragmented(self, msg_type: int, payload: bytes, addr: tuple):
        """
        Send a potentially large response as fragmented UDP packets.

        Fragment header format:
        - protocol_version: 1 byte
        - msg_type: 1 byte
        - request_id: 4 bytes (to correlate fragments)
        - fragment_index: 2 bytes
        - total_fragments: 2 bytes
        - payload_length: 2 bytes
        - checksum: 4 bytes (CRC32 of fragment payload)
        Total header: 16 bytes
        """
        import zlib

        max_payload_per_fragment = MAX_UDP_PAYLOAD - FRAGMENT_HEADER_SIZE
        total_size = len(payload)

        # Calculate number of fragments
        total_fragments = (total_size + max_payload_per_fragment - 1) // max_payload_per_fragment
        if total_fragments == 0:
            total_fragments = 1

        # Limit total fragments to prevent abuse
        max_fragments = 50
        if total_fragments > max_fragments:
            logger.warning(f"Response too large ({total_size} bytes, {total_fragments} fragments), truncating")
            payload = payload[:max_payload_per_fragment * max_fragments]
            total_fragments = max_fragments

        self._request_id_counter = (self._request_id_counter + 1) & 0xFFFFFFFF
        request_id = self._request_id_counter

        for i in range(total_fragments):
            start = i * max_payload_per_fragment
            end = min(start + max_payload_per_fragment, len(payload))
            fragment_payload = payload[start:end]

            checksum = zlib.crc32(fragment_payload) & 0xFFFFFFFF

            header = struct.pack(
                '!BBIHHI',
                PROTOCOL_VERSION,
                msg_type,
                request_id,
                i,              # fragment_index
                total_fragments,
                len(fragment_payload),
            )
            # Append checksum
            header += struct.pack('!I', checksum)

            packet = header + fragment_payload
            self._send_raw(packet, addr)

            # Small delay between fragments to avoid overwhelming the network
            if total_fragments > 1:
                time.sleep(0.001)

        logger.debug(f"Sent {total_fragments} fragment(s) ({total_size} bytes) to {addr}")

    def _send_raw(self, data: bytes, addr: tuple):
        """Send raw bytes to an address."""
        try:
            if self._socket:
                self._socket.sendto(data, addr)
        except OSError as e:
            logger.error(f"Failed to send to {addr}: {e}")

    def _cleanup_loop(self):
        """Periodic cleanup of rate limiter and challenge manager."""
        while self._running:
            time.sleep(self._cleanup_interval)
            self.rate_limiter.cleanup()
            self.challenge_manager.cleanup()


class GameServerBrowserClient:
    """Client for querying game servers - used by server browsers."""

    def __init__(self, timeout: float = 5.0):
        self.timeout = timeout
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self._socket.settimeout(timeout)

    def close(self):
        self._socket.close()

    def ping(self, server_addr: tuple) -> dict:
        """Send a ping request and get basic server info."""
        client_time = time.time()
        payload = struct.pack('!BBd', PROTOCOL_VERSION, MSG_PING_REQUEST, client_time)
        self._socket.sendto(payload, server_addr)

        data, _ = self._socket.recvfrom(4096)

        if len(data) < 12:
            raise ValueError("Invalid ping response")

        protocol_ver, msg_type, echo_time, player_count, max_players = struct.unpack('!BBdBB', data[:12])

        if msg_type != MSG_PING_RESPONSE:
            raise ValueError(f"Unexpected message type: 0x{msg_type:02x}")

        offset = 12
        name_len = data[offset]
        offset += 1
        server_name = data[offset:offset + name_len].decode('utf-8')
        offset += name_len

        map_len = data[offset]
        offset += 1
        map_name = data[offset:offset + map_len].decode('utf-8')

        rtt = time.time() - echo_time

        return {
            "server_name": server_name,
            "map_name": map_name,
            "player_count": player_count,
            "max_players": max_players,
            "ping_ms": round(rtt * 1000, 1),
        }

    def _get_challenge(self, server_addr: tuple) -> int:
        """Request a challenge token from the server."""
        request = struct.pack('!BB', PROTOCOL_VERSION, MSG_CHALLENGE_REQUEST)
        self._socket.sendto(request, server_addr)

        data, _ = self._socket.recvfrom(4096)
        if len(data) < 6:
            raise ValueError("Invalid challenge response")

        protocol_ver, msg_type, challenge = struct.unpack('!BBI', data[:6])
        if msg_type != MSG_CHALLENGE_RESPONSE:
            raise ValueError(f"Unexpected message type: 0x{msg_type:02x}")

        return challenge

    def _receive_fragmented(self, expected_msg_type: int) -> bytes:
        """Receive and reassemble a fragmented response."""
        import zlib

        fragments: Dict[int, bytes] = {}
        total_fragments = None
        request_id = None

        deadline = time.time() + self.timeout

        while time.time() < deadline:
            remaining = deadline - time.time()
            if remaining <= 0:
                break

            self._socket.settimeout(remaining)
            try:
                data, _ = self._socket.recvfrom(2048)
            except socket.timeout:
                break

            if len(data) < FRAGMENT_HEADER_SIZE:
                continue

            protocol_ver, msg_type = struct.unpack('!BB', data[:2])

            # Check for error response
            if msg_type == 0xFF:
                error_code = data[2] if len(data) > 2 else 0
                raise ValueError(f"Server error: code {error_code} (challenge required?)")

            if msg_type != expected_msg_type:
                continue

            rid, frag_idx, total_frags, payload_len = struct.unpack('!IHHI', data[2:12])
            checksum = struct.unpack('!I', data[12:16])[0]
            fragment_payload = data[16:16 + payload_len]

            # Verify checksum
            computed_checksum = zlib.crc32(fragment_payload) & 0xFFFFFFFF
            if computed_checksum != checksum:
                logger.warning(f"Checksum mismatch for fragment {frag_idx}")
                continue

            if request_id is None:
                request_id = rid
                total_fragments = total_frags
            elif rid != request_id:
                continue  # Different request, ignore

            fragments[frag_idx] = fragment_payload

            if len(fragments) == total_fragments:
                break

        if total_fragments is None:
            raise TimeoutError("No response received")

        if len(fragments) != total_fragments:
            raise ValueError(f"Incomplete response: got {len(fragments)}/{total_fragments} fragments")

        # Reassemble
        result = b''
        for i in range(total_fragments):
            if i not in fragments:
                raise ValueError(f"Missing fragment {i}")
            result += fragments[i]

        return result

    def get_status(self, server_addr: tuple) -> dict:
        """Get full server status including player list."""
        challenge = self._get_challenge(server_addr)

        request = struct.pack('!BBI', PROTOCOL_VERSION, MSG_STATUS_REQUEST, challenge)
        self._socket.sendto(request, server_addr)

        response_data = self._receive_fragmented(MSG_STATUS_RESPONSE)
        return json.loads(response_data.decode('utf-8'))

    def get_players(self, server_addr: tuple) -> dict:
        """Get player list."""
        challenge = self._get_challenge(server_addr)

        request = struct.pack('!BBI', PROTOCOL_VERSION, MSG_PLAYER_LIST_REQUEST, challenge)
        self._socket.sendto(request, server_addr)

        response_data = self._receive_fragmented(MSG_PLAYER_LIST_RESPONSE)
        return json.loads(response_data.decode('utf-8'))

    def get_rules(self, server_addr: tuple) -> dict:
        """Get server rules."""
        challenge = self._get_challenge(server_addr)

        request = struct.pack('!BBI', PROTOCOL_VERSION, MSG_RULES_REQUEST, challenge)
        self._socket.sendto(request, server_addr)

        response_data = self._receive_fragmented(MSG_RULES_RESPONSE)
        return json.loads(response_data.decode('utf-8'))


def simulate_game():
    """Run a demo with a server and simulated players, then query it."""
    import random

    server = GameServer(host="127.0.0.1", port=27015)
    server.server_info.server_name = "Epic Fragfest #42"
    server.server_info.map_name = "dm_arena"
    server.server_info.game_mode = "team_deathmatch"
    server.server_info.max_players = 32
    server.server_info.mods = ["instagib", "low_gravity"]
    server.server_info.rules["gravity"] = "400"
    server.server_info.rules["friendly_fire"] = "on"

    # Add simulated players
    player_names = [
        "FragMaster", "NoobSlayer", "CamperKing", "RunNGun",
        "HeadshotHero", "SniperElite", "RocketMan", "ShieldWall",
        "GhostRecon", "StealthKill", "BoomStick", "IronSight",
        "QuickScope", "FlashBang", "SmokeScreen", "NadeSpam",
        "WallBang", "PreFire", "ClutchKing", "AcePlayer",
    ]

    teams = ["Red", "Blue"]

    for name in player_names:
        player = server.add_player(
            name=name,
            team=random.choice(teams),
            ip_address=f"192.168.1.{random.randint(2, 254)}"
        )
        server.update_player(
            player.player_id,
            score=random.randint(0, 100),
            kills=random.randint(0, 50),
            deaths=random.randint(0, 40),
            ping=random.randint(10, 200),
        )

    server.server_info.game_state = GameState.IN_PROGRESS
    server.server_info.elapsed_time = 342.5

    # Start server in a thread
    server_thread = threading.Thread(target=server.start, daemon=True)
    server_thread.start()

    # Give server time to start
    time.sleep(0.5)

    # Now query the server as a client
    client = GameServerBrowserClient(timeout=5.0)

    try:
        print("=" * 60)
        print("GAME SERVER BROWSER - Query Results")
        print("=" * 60)

        # Ping
        print("\n[PING]")
        ping_result = client.ping(("127.0.0.1", 27015))
        print(f"  Server: {ping_result['server_name']}")
        print(f"  Map: {ping_result['map_name']}")
        print(f"  Players: {ping_result['player_count']}/{ping_result['max_players']}")
        print(f"  Ping: {ping_result['ping_ms']}ms")

        # Full status
        print("\n[FULL STATUS]")
        status = client.get_status(("127.0.0.1", 27015))
        server_data = status['server']
        print(f"  Server: {server_data['server_name']}")
        print(f"  Map: {server_data['map_name']}")
        print(f"  Mode: {server_data['game_mode']}")
        print(f"  State: {server_data['game_state']}")
        print(f"  Version: {server_data['server_version']}")
        print(f"  Mods: {', '.join(server_data['mods'])}")
        print(f"  Players: {status['player_count']}/{server_data['max_players']}")

        print(f"\n  {'Name':<20} {'Team':<8} {'Score':<8} {'K/D':<10} {'Ping':<6}")
        print(f"  {'-'*52}")
        for player in sorted(status['players'], key=lambda p: p['score'], reverse=True):
            kd = f"{player['kills']}/{player['deaths']}"
            print(f"  {player['name']:<20} {player['team']:<8} {player['score']:<8} {kd:<10} {player['ping']:<6}")

        # Rules
        print("\n[RULES]")
        rules = client.get_rules(("127.0.0.1", 27015))
        for key, value in rules['rules'].items():
            print(f"  {key}: {value}")

        # Player list
        print("\n[PLAYER LIST]")
        players = client.get_players(("127.0.0.1", 27015))
        print(f"  Total players: {players['player_count']}/{players['max_players']}")

    except Exception as e:
        logger.error(f"Client error: {e}")
        import traceback
        traceback.print_exc()
    finally:
        client.close()
        server.stop()

    print("\n" + "=" * 60)
    print("Demo complete!")


if __name__ == "__main__":
    import sys

    if len(sys.argv) > 1 and sys.argv[1] == "server":
        # Run as standalone server
        server = GameServer(
            host="0.0.0.0",
            port=int(sys.argv[2]) if len(sys.argv) > 2 else 27015
        )
        try:
            server.start()
        except KeyboardInterrupt:
            server.stop()
    elif len(sys.argv) > 1 and sys.argv[1] == "query":
        # Query a server
        target_host = sys.argv[2] if len(sys.argv) > 2 else "127.0.0.1"
        target_port = int(sys.argv[3]) if len(sys.argv) > 3 else 27015
        client = GameServerBrowserClient()
        try:
            print("Pinging server...")
            print(client.ping((target_host, target_port)))
            print("\nGetting status...")
            status = client.get_status((target_host, target_port))
            print(json.dumps(status, indent=2))
        except Exception as e:
            print(f"Error: {e}")
        finally:
            client.close()
    else:
        # Run demo simulation
        simulate_game()